    MAG_INPUT_PC2   : port mag_in_data_y	-> magneto_thread.mag_in_data_y;
    MAG_INPUT_PC3   : port mag_in_data_z	-> magneto_thread.mag_in_data_z;

    GYRO_INPUT_PC1  : port gyro_in_data_x	-> gyro_thread.gyro_in_data_x;
